def self_anneal(max_retries: int = 3, backoff: float = 1.0):
    """Heal & Renew decorator: fail → analyze → fix → retry."""
    def decorator(func):
        @wraps(func)
        async def wrapper(*args, **kwargs):
            last_error = None
            for attempt in range(max_retries):
                try:
                    return await func(*args, **kwargs)
                except Exception as e:
                    last_error = e
                    logger.warning(f"Attempt {attempt + 1} failed: {e}")

                    # Log as training data for future improvements
                    await log_error_for_learning(
                        function=func.__name__,
                        error=str(e),
                        attempt=attempt,
                        context=kwargs
                    )

                    # Exponential backoff
                    await asyncio.sleep(backoff * (2 ** attempt))

            raise SelfAnnealingExhausted(
                f"Failed after {max_retries} attempts",
                last_error=last_error
            )
        return wrapper
    return decorator
